import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as i,c as l,a as t,b as e,d as s,f as a}from"./app-fe0f1b05.js";const d={},p=t("h2",{id:"deepseek-v3-1",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#deepseek-v3-1","aria-hidden":"true"},"#"),e(" DeepSeek-V3.1")],-1),c={href:"https://huggingface.co/collections/deepseek-ai/deepseek-v31",target:"_blank",rel:"noopener noreferrer"},h=t("p",null,"671B-A37B 模型，基于 DeepSeek-V3 架构继续训练和后训练得到的 hybrid model：同一个模型可以通过 chat template 切换 “thinking mode” 和 “non-thinking mode”。",-1),g=t("p",null,"thinking efficiency 更高，long-context extension 更强",-1),m=t("hr",null,null,-1),u=t("h2",{id:"deepseek-v3-2",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#deepseek-v3-2","aria-hidden":"true"},"#"),e(" Deepseek-V3.2")],-1),k={href:"https://huggingface.co/collections/deepseek-ai/deepseek-v32",target:"_blank",rel:"noopener noreferrer"},_={href:"https://arxiv.org/pdf/2512.02556",target:"_blank",rel:"noopener noreferrer"},f=a("<p>V3.2 在 V3.1-Terminus 基础上，引入 DeepSeek Sparse Attention，并进一步强化 reasoning 与 agent 能力</p><hr><ul><li><strong>DeepSeek Sparse Attention</strong> ：V3.2-Exp 引入 DSA，是为了在 long context 下实现 faster and more efficient training &amp; inference</li></ul><p>V3.2 唯一的架构变化就是通过 continued training 引入了 <strong>DeepSeek Sparse Attention</strong> 。</p><p>普通 attention 是每个 token 看所有历史 token，所以长上下文下成本很高。DSA 的做法是：</p><ol><li>用 lightning indexer 给历史 token 打分；</li><li>选出 top-k 个重要 key-value entries；</li><li>只对这些被选中的 token 做主 attention。</li></ol>",6),b=t("p",null,[e("因此，主 attention 的复杂度从 "),t("span",{class:"katex"},[t("span",{class:"katex-mathml"},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("semantics",null,[t("mrow",null,[t("mi",null,"O"),t("mo",{stretchy:"false"},"("),t("msup",null,[t("mi",null,"L"),t("mn",null,"2")]),t("mo",{stretchy:"false"},")")]),t("annotation",{encoding:"application/x-tex"},"O(L^2)")])])]),t("span",{class:"katex-html","aria-hidden":"true"},[t("span",{class:"base"},[t("span",{class:"strut",style:{height:"1.0641em","vertical-align":"-0.25em"}}),t("span",{class:"mord mathnormal",style:{"margin-right":"0.02778em"}},"O"),t("span",{class:"mopen"},"("),t("span",{class:"mord"},[t("span",{class:"mord mathnormal"},"L"),t("span",{class:"msupsub"},[t("span",{class:"vlist-t"},[t("span",{class:"vlist-r"},[t("span",{class:"vlist",style:{height:"0.8141em"}},[t("span",{style:{top:"-3.063em","margin-right":"0.05em"}},[t("span",{class:"pstrut",style:{height:"2.7em"}}),t("span",{class:"sizing reset-size6 size3 mtight"},[t("span",{class:"mord mtight"},"2")])])])])])])]),t("span",{class:"mclose"},")")])])]),e(" 降到 "),t("span",{class:"katex"},[t("span",{class:"katex-mathml"},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("semantics",null,[t("mrow",null,[t("mi",null,"O"),t("mo",{stretchy:"false"},"("),t("mi",null,"L"),t("mi",null,"k"),t("mo",{stretchy:"false"},")")]),t("annotation",{encoding:"application/x-tex"},"O(Lk)")])])]),t("span",{class:"katex-html","aria-hidden":"true"},[t("span",{class:"base"},[t("span",{class:"strut",style:{height:"1em","vertical-align":"-0.25em"}}),t("span",{class:"mord mathnormal",style:{"margin-right":"0.02778em"}},"O"),t("span",{class:"mopen"},"("),t("span",{class:"mord mathnormal"},"L"),t("span",{class:"mord mathnormal",style:{"margin-right":"0.03148em"}},"k"),t("span",{class:"mclose"},")")])])]),e("。")],-1),x=a('<p>DeepSeek 没有从头训练一个 DSA 模型，而是从 DeepSeek-V3.1-Terminus checkpoint 出发，先进行 continued pre-training，再做 post-training。continued pre-training 又分两步：</p><table><thead><tr><th>阶段</th><th>做什么</th><th>目的</th></tr></thead><tbody><tr><td>Dense Warm-up</td><td>冻结主模型，只训练 indexer</td><td>让 indexer 学会模仿 dense attention</td></tr><tr><td>Sparse Training</td><td>启用 top-k 稀疏选择，训练全模型</td><td>让模型适应 DSA 稀疏模式</td></tr></tbody></table><p>这个训练流程的设计很重要，因为如果直接把 dense attention 换成 sparse attention，模型性能可能会明显掉。DeepSeek 用 warm-up + sparse training 的方式平滑过渡。</p><hr><ul><li>Post-Training：Specialist Distillation</li></ul><p>先 RL 训练多个“专家模型”，再让这些专家模型生成高质量数据，最后用这些数据训练统一模型。</p><ul><li>Post-Training：Mixed RL Training</li></ul><p>RL 训练时候把三类目标合并：</p><table><thead><tr><th>训练类型</th><th>目标</th></tr></thead><tbody><tr><td>reasoning RL</td><td>提升数学、代码、逻辑推理</td></tr><tr><td>agent RL</td><td>提升工具调用和多步任务执行</td></tr><tr><td>human alignment RL</td><td>提升回答质量、偏好对齐、通用帮助性</td></tr></tbody></table><ul><li><strong>Post-Training：Scalable RL</strong></li></ul><p>V3.2 的一个核心观点是： <strong>模型能力的提升不只来自 pre-training，也越来越依赖 post-training compute 的扩展</strong> 。</p><p>论文中提到，DeepSeek-V3.2 建立了更稳定、可扩展的 RL protocol，并且 post-training 阶段的计算预算超过了 pre-training cost 的 10%。这说明 DeepSeek 把 RL 不再看作简单的对齐阶段，而是看作继续提升 reasoning / agent 能力的重要 scaling 阶段。</p><p>这里使用的核心 RL 方法仍然是 <strong>GRPO</strong> ，但 V3.2 重点不是提出一个全新的 RL 算法，而是解决大规模 RL 训练中的稳定性问题。</p><p>主要包括：</p><table><thead><tr><th>技巧</th><th>解决的问题</th></tr></thead><tbody><tr><td>Unbiased KL Estimate</td><td>让 KL 约束更稳定，避免训练中梯度异常</td></tr><tr><td>Off-policy Sequence Masking</td><td>避免过旧、偏离当前 policy 的负样本误导训练</td></tr><tr><td>Keep Routing</td><td>MoE 模型中保持 sampling 和 training 时专家路由一致</td></tr><tr><td>Keep Sampling Mask</td><td>保持采样阶段和训练阶段的 token 候选空间一致</td></tr></tbody></table><p>这些技巧说明，V3.2 的 RL scaling 重点不是“换一个算法”，而是让 GRPO 能够在更大规模、更复杂任务上稳定运行。</p><hr><ul><li><strong>Thinking in Tool-Use：把推理接入工具调用</strong></li></ul><p>V3.2 的另一个重点是： <strong>不是单纯让模型会 function calling，而是让模型在 tool-use 过程中保留 reasoning 能力</strong> 。</p><p>在普通多轮工具调用中，如果每次工具返回后模型都丢掉之前的 reasoning，那么模型就需要反复重新思考，导致 token 浪费和 trajectory 变长。</p><p>V3.2 的做法是：</p><ol><li>如果只是 tool output 加入上下文，就保留之前的 reasoning；</li><li>只有当新的 user message 出现时，才丢弃历史 reasoning；</li><li>即使丢弃 reasoning，也保留 tool call 和 tool result 历史。</li></ol><p>这个设计的意义是： <strong>agent 不只是“调用工具”，而是要记住自己为什么调用工具，以及下一步该怎么利用工具结果。</strong></p><hr><ul><li><strong>Large-Scale Agentic Task Synthesis</strong></li></ul><p>V3.2 提出了大规模 agentic task synthesis pipeline，用来生成复杂工具调用任务。论文提到，它们生成了超过 <strong>1,800 个不同环境</strong> 和 <strong>85,000 个复杂 prompts</strong> ，用于推动 agent RL 训练。</p><p>这些任务覆盖多个方向：</p><table><thead><tr><th>Agent 类型</th><th>训练目标</th></tr></thead><tbody><tr><td>Search Agent</td><td>学会搜索、验证信息、整合答案</td></tr><tr><td>Code Agent</td><td>学会修复代码、运行测试、处理真实软件工程任务</td></tr><tr><td>Code Interpreter Agent</td><td>学会在数学、数据分析、逻辑任务中调用代码</td></tr><tr><td>General Agent</td><td>学会在合成环境中完成复杂多步任务</td></tr></tbody></table><p>这里最重要的思想是：</p><blockquote><p>agent 数据不只是人工写 prompt，而是通过自动化 pipeline 生成环境、工具、任务和 verifier。</p></blockquote><p>也就是说，DeepSeek 把 agent training 变成了一个可以 scale 的系统。</p><hr><h2 id="deepseek-v4" tabindex="-1"><a class="header-anchor" href="#deepseek-v4" aria-hidden="true">#</a> DeepSeek V4</h2>',33),y={href:"https://huggingface.co/collections/deepseek-ai/deepseek-v4",target:"_blank",rel:"noopener noreferrer"},S=a("<p>官方发布了两个主要版本：</p><table><thead><tr><th>模型</th><th>总参数</th><th>激活参数</th><th>上下文长度</th><th>定位</th></tr></thead><tbody><tr><td><strong>DeepSeek-V4-Pro</strong></td><td>1.6T</td><td>49B</td><td>1M</td><td>高性能主力模型</td></tr><tr><td><strong>DeepSeek-V4-Flash</strong></td><td>284B</td><td>13B</td><td>1M</td><td>更快、更便宜版本</td></tr></tbody></table><p>对比 3.2，引入了 <strong>Hybrid Attention Architecture</strong> ，在 1M token context 下，V4-Pro 只需要 V3.2 约 27% 的 single-token inference FLOPs，以及 10% 的 KV cache。</p><ul><li>CSA：Compressed Sparse Attention</li></ul><p>CSA 会先把 KV entries 在 sequence 维度上压缩，然后再让 lightning indexer 选择重要的 compressed blocks。Hugging Face 官方博客解释说，CSA 大致是把 token 按块压缩，例如 4x 压缩，再在压缩后的 blocks 上做 sparse selection。</p><ul><li>HCA：Heavily Compressed Attention</li></ul><p>HCA 则是更激进的压缩。官方博客解释说，它会把 KV entries 大幅压缩，例如 128x，然后让 query dense attend 到这些 compressed blocks。因为压缩后序列已经很短，所以 dense attention 成本可以接受。</p><ul><li>mHC：Manifold-Constrained Hyper-Connections</li></ul><p>用于增强传统 residual connections，改进残差连接的方法，目标是让超大 MoE 模型训练更稳定。</p><ul><li>使用了 <strong>Muon optimizer</strong> 训练。</li></ul>",10);function L(V,A){const n=o("ExternalLinkIcon");return i(),l("div",null,[p,t("p",null,[t("a",c,[e("huggingface"),s(n)])]),h,g,m,u,t("p",null,[e("25 年 10 月左右的模型，"),t("a",k,[e("huggingface"),s(n)]),e("，"),t("a",_,[e("arxiv"),s(n)])]),f,b,x,t("p",null,[t("a",y,[e("huggingface"),s(n)])]),S])}const R=r(d,[["render",L],["__file","笔记ds_r_2.html.vue"]]);export{R as default};
